/**
 * Permissive onboarding rule. Walks the entity's `las[]` flat list
 * (synthesised by AtomicFi.RuleEngine.Payload.from_onboarding_entity/2)
 * and emits an empty Control per la_id. Empty Control = no caps,
 * is_blocked: false, block_reason: nil — which is exactly the
 * 'unblock everything' fallback the corpus needs.
 */
export const handler = async (input) => {
  const las = input.las || [];
  const ledger_accounts = {};
  for (const la of las) {
    ledger_accounts[la.id] = {};
  }
  return { ledger_accounts };
};
